pan":24}],"apiConfig":{"listUrl":"/ai/crud/crm_customer/page","detailUrl":"/ai/crud/crm_customer/:id","saveUrl":"/ai/crud/crm_customer","updateUrl":"/ai/crud/crm_customer","deleteUrl":"/ai/crud/crm_customer/:id","importUrl":"/ai/crud/crm_customer/import","exportUrl":"/ai/crud/crm_customer/export","importTemplateUrl":"/ai/crud/crm_customer/import-template"},"options":{"layoutType":"simple-crud","enableImport":true,"enableExport":true,"enableBatchDelete":true,"enableDetail":true,"rowKey":"id"}}',
       1, 1, NOW(), 1, @crm_domain_id, 'CRM', 'CUSTOMER', '客户',
       1, NOW(), 1, 1, NOW()
WHERE @crm_domain_id IS NOT NULL
  AND NOT EXISTS (
    SELECT 1
    FROM ai_crud_config
    WHERE tenant_id = 1
      AND config_key = 'crm_customer'
  );

-- 6. 更新 ai_business_object 表中客户对象的 model_id 字段
UPDATE ai_business_object
SET model_id = @customer_model_id
WHERE tenant_id = 1
  AND suite_code = 'CRM'
  AND object_code = 'CUSTOMER'
  AND model_id IS NULL
  AND @customer_model_id IS NOT NULL;

-- 7. 初始化 CRM 客户应用入口的 config_key 关联（如果不存在）
UPDATE ai_business_app
SET config_key = 'crm_customer'
WHERE tenant_id = 1
  AND app_code = 'CRM_CUSTOMER_MANAGE'
  AND (config_key IS NULL OR config_key = '');
